  // Give some times for Bricks to init the sliders
  setTimeout(() => {
    // Please replace rrbqsp to your Slider element ID !!NOT CSS ID!!
    const mySlider = window.bricksData?.splideInstances['rlhjev'] || false
    // Please replace the button classes to suit your scenario
    const myPrevBtn = document.querySelector('.slider-prev')
    const myNextBtn = document.querySelector('.slider-next')

    if (mySlider && myPrevBtn && myNextBtn) {
      // Add click event handlers for your custom buttons
      myPrevBtn.addEventListener('click', function () {
        mySlider.go('-1') // go() function by SplideJS
      })
      myNextBtn.addEventListener('click', function () {
        mySlider.go('+1') // go() function by SplideJS
      })
    }
  }, 250)
})","executeCode":true,"noRoot":true},"themeStyles":[]}],"source":"bricksCopiedElements","sourceUrl":"https://renmoe.com/bricksnativeglobal","version":"1.12.3","globalClasses":[{"id":"jkkjia","name":"ren-pad-top-bottom-lg","settings":{"_padding":{"bottom":"var(--spacing-lg)","top":"var(--spacing-lg)"}}},{"id":"zbmxmc","name":"ren-gap-lg","settings":{"_columnGap":"var(--spacing-lg)","_rowGap":"var(--spacing-lg)"}},{"id":"lmhszm","name":"ren-overflow-hidden","settings":{"_cssCustom":".ren-overflow-hidden {
